The complete rewritten file:

```typescript
import { Router } from "express";
import {
  listProducts,
  getProductById,
  adjustProductStock,
} from "../services/product-service.js";
import { ServiceError } from "../services/service-error.js";

const router = Router();

router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const result = listProducts({
    category: typeof category === "string" ? category : undefined,
    minPrice: typeof minPrice === "string" ? minPrice : undefined,
    maxPrice: typeof maxPrice === "string" ? maxPrice : undefined,
  });

  res.json(result);
});

router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const result = getProductById(id);
    res.json(result);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body as { adjustment: unknown };
    const result = adjustProductStock(id, adjustment);
    res.json(result);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

export { router as productRouter };
```

A few important details here:

- `listProducts` never throws (it merely returns an empty list when no products match), so `GET /products` needs no `try/catch`.
- The route handler receives `req.body` as `{ adjustment: unknown }` and passes the raw value to the service, which is responsible for the `typeof adjustment !== "number"` guard. This keeps the handler free of validation logic.
- The `typeof category === "string"` guard in the route handler is a pure HTTP layer concern: `req.query` values can be `string | string[] | ParsedQs | ParsedQs[]`, so narrowing to `string | undefined` before passing to the service is appropriate at the transport layer. The service accepts a clean `string | undefined`, not a raw Express query object.

