import { orders, products, getNextOrderId } from "../data.js";
import type { CreateOrderInput, Order, OrderItem } from "../types.js";
import { ServiceError } from "./service-error.js";

export interface OrderFilters {
  userId?: string;
  status?: string;
}

export interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"];

const STATUS_TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    const uid = parseInt(filters.userId, 10);
    if (!isNaN(uid)) {
      filtered = filtered.filter((o) => o.userId === uid);
    }
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrderById(id: number): EnrichedOrder {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  const enrichedItems: EnrichedOrderItem[] = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(input: CreateOrderInput): Order {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ServiceError(400, "userId and items are required");
  }

  if (input.items.length === 0) {
    throw new ServiceError(400, "Order must have at least one item");
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);

    if (!product) {
      throw new ServiceError(400, `Product ${item.productId} not found`);
    }

    if (item.quantity <= 0) {
      throw new ServiceError(400, "Quantity must be positive");
    }

    if (product.stock < item.quantity) {
      throw new ServiceError(400, `Insufficient stock for ${product.name}`);
    }

    product.stock -= item.quantity;

    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });

    total += product.price * item.quantity;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}

export function updateOrderStatus(id: number, status: unknown): Order {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  if (typeof status !== "string" || !VALID_STATUSES.includes(status)) {
    throw new ServiceError(
      400,
      `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`
    );
  }

  if (!STATUS_TRANSITIONS[order.status]?.includes(status)) {
    throw new ServiceError(
      400,
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = status as Order["status"];

  return order;
}

